import React, { useState, useEffect } from 'react';
import { useTheme } from '../context/ThemeContext';
import { useLanguage } from '../context/LanguageContext';
import axios from 'axios';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Package, 
  Plus, 
  Trash2, 
  Factory, 
  Leaf, 
  Recycle,
  ShoppingBag,
  Edit3,
  Eye,
  Zap,
  Clock,
  Scale
} from 'lucide-react';
import ProductWizard from '../components/ProductWizard';
import ProductSaleModal from '../components/ProductSaleModal';

const API_URL = process.env.REACT_APP_BACKEND_URL || '';

const Products = () => {
  const { isDark } = useTheme();
  const { t } = useLanguage();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showWizard, setShowWizard] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [editingProduct, setEditingProduct] = useState(null);

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const response = await axios.get(`${API_URL}/api/products`);
      setProducts(response.data || []);
    } catch (error) {
      console.error('Failed to fetch products:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteProduct = async (productId) => {
    if (!window.confirm('Êtes-vous sûr de vouloir supprimer ce produit ?')) return;
    try {
      await axios.delete(`${API_URL}/api/products/${productId}`);
      fetchProducts();
    } catch (error) {
      console.error('Failed to delete product:', error);
    }
  };

  const handleEditProduct = (product) => {
    if (product.is_enhanced) {
      setEditingProduct(product);
      setShowWizard(true);
    }
  };

  const handleRecordSale = (product) => {
    setSelectedProduct(product);
    setShowSaleModal(true);
  };

  const getTotalSales = (product) => {
    if (!product.sales || product.sales.length === 0) return { quantity: 0, emissions: 0 };
    return product.sales.reduce((acc, sale) => ({
      quantity: acc.quantity + sale.quantity,
      emissions: acc.emissions + (sale.total_emissions || sale.emissions || 0)
    }), { quantity: 0, emissions: 0 });
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div data-testid="products-page" className="space-y-8">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className={`text-3xl font-bold ${isDark ? 'text-white' : 'text-gray-900'}`}>
            {t('products.title')}
          </h1>
          <p className={`mt-2 ${isDark ? 'text-slate-400' : 'text-gray-500'}`}>
            Gérez vos fiches produits et leurs impacts carbone sur tout le cycle de vie
          </p>
        </div>
        <button
          onClick={() => {
            setEditingProduct(null);
            setShowWizard(true);
          }}
          data-testid="add-product-btn"
          className="flex items-center gap-2 px-6 py-3 bg-blue-500 text-white rounded-xl hover:bg-blue-600 transition-all shadow-lg shadow-blue-500/30"
        >
          <Plus className="w-5 h-5" />
          Créer une fiche produit
        </button>
      </div>

      {/* Products Grid */}
      {products.length === 0 ? (
        <div className={`text-center py-16 rounded-2xl ${isDark ? 'bg-slate-800' : 'bg-white shadow-lg'}`}>
          <Package className={`w-16 h-16 mx-auto mb-4 ${isDark ? 'text-slate-600' : 'text-gray-300'}`} />
          <p className={`text-lg mb-2 ${isDark ? 'text-slate-400' : 'text-gray-500'}`}>
            Aucun produit défini
          </p>
          <p className={`text-sm mb-6 ${isDark ? 'text-slate-500' : 'text-gray-400'}`}>
            Créez votre première fiche produit pour commencer à suivre les émissions de vos produits vendus.
          </p>
          <button
            onClick={() => setShowWizard(true)}
            className="inline-flex items-center gap-2 px-6 py-3 bg-blue-500 text-white rounded-xl hover:bg-blue-600 transition-all"
          >
            <Plus className="w-5 h-5" />
            Créer une fiche produit
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {products.map((product, index) => {
            const isEnhanced = product.is_enhanced;
            const salesInfo = getTotalSales(product);
            
            return (
              <motion.div
                key={product.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.05 }}
                className={`rounded-2xl overflow-hidden ${isDark ? 'bg-slate-800' : 'bg-white shadow-lg'}`}
              >
                {/* Header with type badge */}
                <div className={`p-4 ${isEnhanced ? 'bg-gradient-to-r from-purple-500 to-purple-600' : 'bg-gradient-to-r from-gray-400 to-gray-500'}`}>
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-xl bg-white/20 flex items-center justify-center">
                        <Package className="w-5 h-5 text-white" />
                      </div>
                      <div>
                        <h3 className="text-white font-semibold">{product.name}</h3>
                        <p className="text-white/70 text-xs">
                          {isEnhanced 
                            ? (product.product_type === 'semi_finished' ? 'Semi-fini' : 'Fini')
                            : 'Fiche simple'
                          }
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-1">
                      {isEnhanced && (
                        <button
                          onClick={() => handleEditProduct(product)}
                          className="p-2 rounded-lg bg-white/20 hover:bg-white/30 transition-colors"
                          title="Modifier"
                        >
                          <Edit3 className="w-4 h-4 text-white" />
                        </button>
                      )}
                      <button
                        onClick={() => handleDeleteProduct(product.id)}
                        className="p-2 rounded-lg bg-white/20 hover:bg-red-500/50 transition-colors"
                        title="Supprimer"
                      >
                        <Trash2 className="w-4 h-4 text-white" />
                      </button>
                    </div>
                  </div>
                </div>
                
                {/* Content */}
                <div className="p-4 space-y-4">
                  {isEnhanced ? (
                    <>
                      {/* Enhanced product details */}
                      <div className="flex items-center gap-4 text-sm">
                        <div className="flex items-center gap-1.5">
                          <Clock className={`w-4 h-4 ${isDark ? 'text-slate-400' : 'text-gray-400'}`} />
                          <span className={isDark ? 'text-slate-300' : 'text-gray-600'}>
                            {product.lifespan_years} an(s)
                          </span>
                        </div>
                        <div className="flex items-center gap-1.5">
                          <Scale className={`w-4 h-4 ${isDark ? 'text-slate-400' : 'text-gray-400'}`} />
                          <span className={isDark ? 'text-slate-300' : 'text-gray-600'}>
                            {product.materials?.length || 0} matière(s)
                          </span>
                        </div>
                      </div>
                      
                      {/* Emissions breakdown */}
                      <div className="space-y-2">
                        {product.transformation_emissions > 0 && (
                          <div className="flex items-center justify-between text-sm">
                            <span className="flex items-center gap-2">
                              <Factory className="w-4 h-4 text-orange-500" />
                              <span className={isDark ? 'text-slate-300' : 'text-gray-600'}>Transformation</span>
                            </span>
                            <span className={isDark ? 'text-white' : 'text-gray-900'}>
                              {product.transformation_emissions?.toFixed(3)} kgCO₂e
                            </span>
                          </div>
                        )}
                        <div className="flex items-center justify-between text-sm">
                          <span className="flex items-center gap-2">
                            <Leaf className="w-4 h-4 text-green-500" />
                            <span className={isDark ? 'text-slate-300' : 'text-gray-600'}>Utilisation</span>
                          </span>
                          <span className={isDark ? 'text-white' : 'text-gray-900'}>
                            {(product.usage_emissions || 0).toFixed(3)} kgCO₂e
                          </span>
                        </div>
                        <div className="flex items-center justify-between text-sm">
                          <span className="flex items-center gap-2">
                            <Recycle className="w-4 h-4 text-blue-500" />
                            <span className={isDark ? 'text-slate-300' : 'text-gray-600'}>Fin de vie</span>
                          </span>
                          <span className={isDark ? 'text-white' : 'text-gray-900'}>
                            {(product.disposal_emissions || 0).toFixed(3)} kgCO₂e
                          </span>
                        </div>
                      </div>
                    </>
                  ) : (
                    <>
                      {/* Legacy product details */}
                      <div className="space-y-2">
                        <div className="flex items-center justify-between text-sm">
                          <span className="flex items-center gap-2">
                            <Factory className="w-4 h-4 text-orange-500" />
                            <span className={isDark ? 'text-slate-300' : 'text-gray-600'}>Fabrication</span>
                          </span>
                          <span className={isDark ? 'text-white' : 'text-gray-900'}>
                            {product.manufacturing_emissions} kgCO₂e
                          </span>
                        </div>
                        <div className="flex items-center justify-between text-sm">
                          <span className="flex items-center gap-2">
                            <Leaf className="w-4 h-4 text-green-500" />
                            <span className={isDark ? 'text-slate-300' : 'text-gray-600'}>Utilisation</span>
                          </span>
                          <span className={isDark ? 'text-white' : 'text-gray-900'}>
                            {product.usage_emissions} kgCO₂e
                          </span>
                        </div>
                        <div className="flex items-center justify-between text-sm">
                          <span className="flex items-center gap-2">
                            <Recycle className="w-4 h-4 text-blue-500" />
                            <span className={isDark ? 'text-slate-300' : 'text-gray-600'}>Fin de vie</span>
                          </span>
                          <span className={isDark ? 'text-white' : 'text-gray-900'}>
                            {product.disposal_emissions} kgCO₂e
                          </span>
                        </div>
                      </div>
                    </>
                  )}

                  {/* Total emissions */}
                  <div className={`p-3 rounded-xl ${isDark ? 'bg-slate-700' : 'bg-gray-100'}`}>
                    <div className="flex items-center justify-between">
                      <span className={`font-medium ${isDark ? 'text-white' : 'text-gray-900'}`}>
                        Total par unité
                      </span>
                      <span className="text-lg font-bold text-purple-500">
                        {(product.total_emissions_per_unit || 0).toFixed(3)} kgCO₂e
                      </span>
                    </div>
                  </div>

                  {/* Sales info */}
                  {salesInfo.quantity > 0 && (
                    <div className={`text-sm ${isDark ? 'text-slate-400' : 'text-gray-500'}`}>
                      {salesInfo.quantity} unités vendues • {(salesInfo.emissions / 1000).toFixed(2)} tCO₂e générés
                    </div>
                  )}

                  {/* Record Sale Button */}
                  {isEnhanced && (
                    <button
                      onClick={() => handleRecordSale(product)}
                      data-testid={`record-sale-${product.id}`}
                      className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-gradient-to-r from-green-500 to-green-600 text-white rounded-xl hover:from-green-600 hover:to-green-700 transition-all"
                    >
                      <ShoppingBag className="w-5 h-5" />
                      Enregistrer des ventes
                    </button>
                  )}
                </div>
              </motion.div>
            );
          })}
        </div>
      )}

      {/* Product Wizard Modal */}
      <ProductWizard
        isOpen={showWizard}
        onClose={() => {
          setShowWizard(false);
          setEditingProduct(null);
        }}
        onProductCreated={fetchProducts}
        editingProduct={editingProduct}
      />

      {/* Product Sale Modal */}
      <ProductSaleModal
        isOpen={showSaleModal}
        onClose={() => {
          setShowSaleModal(false);
          setSelectedProduct(null);
        }}
        onSaleRecorded={fetchProducts}
        preselectedProduct={selectedProduct}
      />
    </div>
  );
};

export default Products;
